namespace sv_42a71cc65b3f409e9e6179a90be45a15.Client;

public sealed class UserInfo
{
    public required string Email { get; init; }
    public required string[] Roles { get; init; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_42a71cc65b3f409e9e6179a90be45a15.Client;

/// <summary>
/// Client-side AuthenticationStateProvider that rehydrates user identity
/// from PersistentComponentState (serialized by the server during prerendering).
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authenticationStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState state)
    {
        if (!state.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo) || userInfo is null)
        {
            _authenticationStateTask = _unauthenticated;
            return;
        }

        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, userInfo.Email),
            new(ClaimTypes.Email, userInfo.Email),
        };

        foreach (var role in userInfo.Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        _authenticationStateTask = Task.FromResult(
            new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity(claims, "PersistentAuth"))));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authenticationStateTask;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_42a71cc65b3f409e9e6179a90be45a15.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that simulates a logged-in user
/// with hardcoded claims. No database required.
/// </summary>
public sealed class HardcodedAuthenticationStateProvider : AuthenticationStateProvider
{
    private readonly Task<AuthenticationState> _authenticationState;

    public HardcodedAuthenticationStateProvider()
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, "HardcodedAuth");
        var user = new ClaimsPrincipal(identity);

        _authenticationState = Task.FromResult(new AuthenticationState(user));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authenticationState;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_42a71cc65b3f409e9e6179a90be45a15.Client;

namespace sv_42a71cc65b3f409e9e6179a90be45a15.Auth;

/// <summary>
/// Subscribes to AuthenticationStateProvider and persists the user's info
/// into PersistentComponentState so that the client-side WASM runtime can
/// rehydrate the identity after interactive rendering activates.
/// </summary>
public sealed class PersistingAuthenticationStateProvider : IHostEnvironmentAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _state;
    private readonly AuthenticationStateProvider _authStateProvider;
    private readonly PersistingComponentStateSubscription _subscription;

    private Task<AuthenticationState>? _authenticationStateTask;

    public PersistingAuthenticationStateProvider(
        PersistentComponentState state,
        AuthenticationStateProvider authStateProvider)
    {
        _state = state;
        _authStateProvider = authStateProvider;

        AuthenticationStateChanged(authStateProvider.GetAuthenticationStateAsync());
        authStateProvider.AuthenticationStateChanged += AuthenticationStateChanged;
        _subscription = state.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public void SetAuthenticationState(Task<AuthenticationState> authenticationStateTask)
    {
        _authenticationStateTask = authenticationStateTask;
    }

    private void AuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authenticationStateTask = task;
    }

    private async Task OnPersistingAsync()
    {
        var authState = await (_authenticationStateTask ?? _authStateProvider.GetAuthenticationStateAsync());
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var email = principal.FindFirst(ClaimTypes.Email)?.Value ?? principal.Identity.Name ?? "";
            var roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();

            _state.PersistAsJson(nameof(UserInfo), new UserInfo
            {
                Email = email,
                Roles = roles,
            });
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
        _authStateProvider.AuthenticationStateChanged -= AuthenticationStateChanged;
    }
}

