+using System.Security.Claims;
+using Microsoft.AspNetCore.Components.Authorization;
+
+namespace sv_42a71cc65b3f409e9e6179a90be45a15.Auth;
+
+/// <summary>
+/// Server-side AuthenticationStateProvider that simulates a logged-in user
+/// with hardcoded claims. No database required.
+/// </summary>
+public sealed class HardcodedAuthenticationStateProvider : AuthenticationStateProvider
+{
+    private readonly Task<AuthenticationState> _authenticationState;
+
+    public HardcodedAuthenticationStateProvider()
+    {
+        var claims = new[]
+        {
+            new Claim(ClaimTypes.Name, "bob@example.com"),
+            new Claim(ClaimTypes.Email, "bob@example.com"),
+            new Claim(ClaimTypes.Role, "User"),
+            new Claim(ClaimTypes.Role, "Editor"),
+        };
+
+        var identity = new ClaimsIdentity(claims, "HardcodedAuth");
+        var user = new ClaimsPrincipal(identity);
+
+        _authenticationState = Task.FromResult(new AuthenticationState(user));
+    }
+
+    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authenticationState;
+}
+

