using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_42a71cc65b3f409e9e6179a90be45a15.Client;

namespace sv_42a71cc65b3f409e9e6179a90be45a15.Auth;

/// <summary>
/// Subscribes to AuthenticationStateProvider and persists the user's info
/// into PersistentComponentState so that the client-side WASM runtime can
/// rehydrate the identity after interactive rendering activates.
/// </summary>
public sealed class PersistingAuthenticationStateProvider : IHostEnvironmentAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _state;
    private readonly AuthenticationStateProvider _authStateProvider;
    private readonly PersistingComponentStateSubscription _subscription;

    private Task<AuthenticationState>? _authenticationStateTask;

    public PersistingAuthenticationStateProvider(
        PersistentComponentState state,
        AuthenticationStateProvider authStateProvider)
    {
        _state = state;
        _authStateProvider = authStateProvider;

        AuthenticationStateChanged(authStateProvider.GetAuthenticationStateAsync());
        authStateProvider.AuthenticationStateChanged += AuthenticationStateChanged;
        _subscription = state.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public void SetAuthenticationState(Task<AuthenticationState> authenticationStateTask)
    {
        _authenticationStateTask = authenticationStateTask;
    }

    private void AuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authenticationStateTask = task;
    }

    private async Task OnPersistingAsync()
    {
        var authState = await (_authenticationStateTask ?? _authStateProvider.GetAuthenticationStateAsync());
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var email = principal.FindFirst(ClaimTypes.Email)?.Value ?? principal.Identity.Name ?? "";
            var roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();

            _state.PersistAsJson(nameof(UserInfo), new UserInfo
            {
                Email = email,
                Roles = roles,
            });
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
        _authStateProvider.AuthenticationStateChanged -= AuthenticationStateChanged;
    }
}

