using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_42a71cc65b3f409e9e6179a90be45a15.Client;

namespace sv_42a71cc65b3f409e9e6179a90be45a15.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that simulates a logged-in user
/// with hardcoded claims and persists the auth state to PersistentComponentState
/// so that the WASM client can rehydrate it.
/// </summary>
public sealed class HardcodedAuthenticationStateProvider : AuthenticationStateProvider, IDisposable
{
    private readonly Task<AuthenticationState> _authenticationState;
    private readonly PersistingComponentStateSubscription _subscription;

    public HardcodedAuthenticationStateProvider(PersistentComponentState state)
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, "HardcodedAuth");
        var user = new ClaimsPrincipal(identity);

        _authenticationState = Task.FromResult(new AuthenticationState(user));

        _subscription = state.RegisterOnPersisting(() =>
        {
            state.PersistAsJson(nameof(UserInfo), new UserInfo
            {
                Email = "bob@example.com",
                Roles = new[] { "User", "Editor" },
            });
            return Task.CompletedTask;
        }, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authenticationState;

    public void Dispose() => _subscription.Dispose();
}

